INSERT INTO `article` (`id`, `title`, `context`, `publisher_id`, `image`, `is_illegal`, `status`, `like_num`, `create_time`, `update_time`) VALUES
(4, 'Spring Boot入门教程', '<p>Spring Boot是基于Spring框架的开发工具，它可以快速创建独立运行的、生产级别的Spring应用程序。本教程将带你了解Spring Boot的核心概念和基本使用方法。</p><p>首先，我们需要创建一个Spring Boot项目，可以使用Spring Initializr或者IDE插件来快速生成项目骨架。</p>', 1, '/images/spring-boot.png', 0, '已发布', 15, '2026-04-05 09:00:00', '2026-04-05 09:00:00'),
(5, 'Java并发编程实战', '<p>并发编程是Java开发中的重要技能。本文将介绍多线程编程的基本概念、线程同步机制、线程池的使用等内容。</p><p>在实际开发中，合理使用并发可以提高程序的性能，但也要注意线程安全问题。</p>', 2, '/images/concurrent.jpg', 0, '已发布', 23, '2026-04-05 10:30:00', '2026-04-05 10:30:00'),
(6, 'MySQL数据库优化技巧', '<p>数据库优化是提升系统性能的关键。本文将从索引优化、查询优化、表结构优化等多个角度介绍MySQL的性能调优方法。</p><p>合理的索引设计可以大幅提升查询效率，但也要注意索引的维护成本。</p>', 1, '/images/mysql.png', 0, '已发布', 18, '2026-04-05 11:15:00', '2026-04-05 11:15:00'),
(7, 'Vue3组合式API详解', '<p>Vue3引入了组合式API（Composition API），这是一种基于函数的API，可以更灵活地组织组件逻辑。</p><p>相比于选项式API，组合式API提供了更好的代码组织和复用能力。</p>', 3, '/images/vue3.jpg', 0, '已发布', 12, '2026-04-05 12:00:00', '2026-04-05 12:00:00'),
(8, 'Redis缓存实战应用', '<p>Redis是一个高性能的键值对数据库，常用于缓存、消息队列等场景。本文将介绍Redis在Web应用中的实际应用。</p><p>合理使用缓存可以减轻数据库压力，提高系统吞吐量。</p>', 2, '/images/redis.png', 0, '已发布', 31, '2026-04-05 13:45:00', '2026-04-05 13:45:00'),
(9, 'Docker容器化部署指南', '<p>Docker可以将应用及其依赖打包成一个轻量级的容器，实现"一次构建，到处运行"。</p><p>本文将详细介绍Docker的安装、镜像构建、容器管理等操作。</p>', 4, '/images/docker.jpg', 0, '已发布', 27, '2026-04-05 14:20:00', '2026-04-05 14:20:00'),
(10, '设计模式之单例模式', '<p>单例模式是最常用的设计模式之一，它确保一个类只有一个实例，并提供一个全局访问点。</p><p>本文将介绍单例模式的几种实现方式及其优缺点。</p>', 3, '/images/singleton.png', 0, '已发布', 9, '2026-04-05 15:10:00', '2026-04-05 15:10:00'),
(11, 'Git版本控制最佳实践', '<p>Git是目前最流行的版本控制系统。掌握Git的使用对于团队协作开发至关重要。</p><p>本文将分享Git的常用命令、分支管理策略以及代码审查流程。</p>', 5, '/images/git.jpg', 0, '已发布', 45, '2026-04-05 16:00:00', '2026-04-05 16:00:00'),
(12, '微服务架构设计思考', '<p>微服务架构将单一应用程序划分成一组小的服务，每个服务运行在自己的进程中。</p><p>本文将探讨微服务的优势、挑战以及落地实践中的注意事项。</p>', 4, '/images/microservice.png', 0, '已发布', 38, '2026-04-05 17:30:00', '2026-04-05 17:30:00'),
(13, '前端性能优化实践', '<p>前端性能优化直接影响用户体验。本文将从资源加载、渲染性能、代码优化等方面分享优化技巧。</p><p>合理的性能优化可以让页面加载更快，交互更流畅。</p>', 6, '/images/frontend.jpg', 0, '已发布', 22, '2026-04-05 18:15:00', '2026-04-05 18:15:00'),
(14, 'Linux常用命令大全', '<p>Linux是服务器端的主流操作系统。掌握常用命令是运维和开发的基本技能。</p><p>本文整理了日常开发中最常用的Linux命令及其使用场景。</p>', 5, '/images/linux.png', 0, '已发布', 33, '2026-04-05 19:00:00', '2026-04-05 19:00:00'),
(15, 'Python数据分析入门', '<p>Python在数据分析领域有着广泛的应用。本文将介绍pandas、numpy等核心库的使用方法。</p><p>数据分析可以帮助我们从数据中发现规律，支持决策。</p>', 7, '/images/python.jpg', 0, '已发布', 19, '2026-04-05 20:30:00', '2026-04-05 20:30:00'),
(16, '网络安全防护策略', '<p>网络安全是互联网应用的生命线。本文将介绍常见的安全威胁和防护措施。</p><p>做好安全防护可以保护用户数据，维护系统稳定。</p>', 6, '/images/security.png', 0, '已发布', 28, '2026-04-06 08:00:00', '2026-04-06 08:00:00'),
(17, '算法与数据结构精讲', '<p>算法和数据结构是程序员的内功。本文将介绍常用数据结构和经典算法的实现。</p><p>扎实的算法基础可以帮助我们写出更高效的代码。</p>', 8, '/images/algorithm.jpg', 0, '已发布', 41, '2026-04-06 09:30:00', '2026-04-06 09:30:00'),
(18, '单元测试最佳实践', '<p>单元测试是保证代码质量的重要手段。本文将介绍JUnit、Mockito等测试框架的使用。</p><p>良好的测试习惯可以提高代码的可靠性和可维护性。</p>', 7, '/images/testing.png', 0, '已发布', 16, '2026-04-06 10:45:00', '2026-04-06 10:45:00'),
(19, '消息队列应用场景', '<p>消息队列是分布式系统中的重要组件。本文将介绍RabbitMQ、Kafka等消息中间件的使用。</p><p>消息队列可以实现异步处理、系统解耦等功能。</p>', 9, '/images/mq.jpg', 0, '已发布', 24, '2026-04-06 12:00:00', '2026-04-06 12:00:00'),
(20, '代码规范与重构技巧', '<p>良好的代码规范是团队协作的基础。本文将分享代码风格、命名规范以及重构方法。</p><p>清晰的代码可以让团队协作更高效，降低维护成本。</p>', 8, '/images/cleanup.png', 0, '已发布', 37, '2026-04-06 13:30:00', '2026-04-06 13:30:00'),
(21, '机器学习基础入门', '<p>机器学习是人工智能的核心技术。本文将介绍机器学习的基本概念和常用算法。</p><p>掌握机器学习可以为未来的技术发展打下基础。</p>', 10, '/images/ml.png', 0, '已发布', 52, '2026-04-06 14:15:00', '2026-04-06 14:15:00'),
(22, '云计算服务选型指南', '<p>云计算提供了弹性、可靠的计算资源。本文将介绍主流云服务商的产品和选型建议。</p><p>合理选择云服务可以降低成本，提高系统可用性。</p>', 9, '/images/cloud.jpg', 0, '已发布', 30, '2026-04-06 15:45:00', '2026-04-06 15:45:00'),
(23, '敏捷开发实践分享', '<p>敏捷开发是一种灵活的项目管理方法。本文将介绍Scrum、Kanban等敏捷框架的使用。</p><p>敏捷开发可以提高团队效率，快速响应需求变化。</p>', 11, '/images/agile.png', 0, '已发布', 21, '2026-04-06 17:00:00', '2026-04-06 17:00:00'),
(24, 'TypeScript进阶指南', '<p>TypeScript是JavaScript的超集，提供了静态类型检查。本文将介绍TS的高级特性。</p><p>使用TypeScript可以提高代码的健壮性和可维护性。</p>', 10, '/images/typescript.jpg', 0, '已发布', 26, '2026-04-06 18:30:00', '2026-04-06 18:30:00');